const employee = {
  name: 'Ali',
  basicSalary: 5000,
  bonusPercentage: 20,
  calcBonus: function() {
    this.bonus = this.basicSalary * this.bonusPercentage / 100;
    return this.bonus;
  },
  calcTotalSalary: function() {
    this.calcBonus();
    this.totalSalary = this.basicSalary + this.bonus;
    return this.totalSalary;
  },
  getPaySlip: function() {
    this.calcTotalSalary();
    return `${this.name}: Basic ${this.basicSalary}, Bonus ${this.bonus}, Total ${this.totalSalary}`;
  },
};

console.log(employee.getPaySlip());

const student = {
  name: 'Nour',
  scores: [85, 92, 78, 95, 88],
  calcAverage: function() {
    let sum = 0;
    for (let i = 0; i < this.scores.length; i++) sum += this.scores[i];
    this.average = sum / this.scores.length;
    return this.average;
  },
  getHighest: function() {
    this.highest = Math.max(...this.scores);
    return this.highest;
  },
  getLowest: function() {
    this.lowest = Math.min(...this.scores);
    return this.lowest;
  },
  getGrade: function() {
    this.calcAverage();
    this.grade = this.average >= 90 ? 'A' : this.average >= 80 ? 'B' : this.average >= 70 ? 'C' : 'F';
    return this.grade;
  },
  getReport: function() {
    this.getGrade();
    this.getHighest();
    this.getLowest();
    return `${this.name}: Average ${this.average}, Grade ${this.grade}, Highest ${this.highest}, Lowest ${this.lowest}`;
  },
};

console.log(student.getReport());

